INSERT INTO `goods_info` VALUES (1, 'SK-II', '这是最好用的SK-II', 1900.00, 0.80, 36, 5120, '否', 20, 1, '[47]', 1, 1);
INSERT INTO `goods_info` VALUES (2, '资生堂', '这是资生堂', 299.00, 0.80, 13, 384, '是', 17, 2, '[28]', 1, 1);
INSERT INTO `goods_info` VALUES (3, '雅诗兰黛眼霜', '这是雅诗兰黛眼霜', 199.00, 0.80, 32, 8196, '否', 6, 3, '[30]', 1, 1);
INSERT INTO `goods_info` VALUES (4, '雅诗兰黛精华液', '这是雅诗兰黛精华液', 199.00, 0.90, 2, 1, '否', 16, 3, '[29]', 1, 1);
INSERT INTO `goods_info` VALUES (5, '娇韵诗', '这是娇韵诗', 8.90, 0.90, 12, 0, '是', 0, 4, '[34]', 1, 1);
INSERT INTO `goods_info` VALUES (6, '资生堂护肤液', '这是资生堂护肤液', 299.00, 0.90, 3, 0, '是', 19, 2, '[33]', 1, 1);
INSERT INTO `goods_info` VALUES (8, '雅诗兰黛 DW 持妆粉底液', '质地与妆效：半流动质地，细腻易推开，呈现自然哑光妆效，妆感清透不厚重。 核心功效：主打控油、持久、遮瑕，具有卓越的控油力，能有效吸附油脂，保持肌肤清爽；遮瑕力强，可遮盖六七成瑕疵，如痘印、斑点、红血丝等；持妆效果出色，可长达 8 小时甚至更久，不易脱妆、斑驳。 适用肤质：油皮、混油皮的首选，混干皮在夏天也可尝试。 价格：一般为 30ml/470 元左右。 色号选择：色号丰富，以 “数字 + 字母 + 数字” 的形式命名，如 1W1、2C0 等，字母 W 代表黄调，N 代表中性，C 代表粉调，前面的数字表示色调的浓度，数字越大浓度越大', 470.00, 0.90, 0, 0, '是', 20, 3, '[53]', 5, 1);
INSERT INTO `goods_info` VALUES (9, '雅诗兰黛沁水粉底液', '质地与妆效：乳液质地，丝滑易推开，流动性较强，上脸后呈现奶油肌妆效，轻薄自然，不假白，肌肤看起来水润有光泽。 核心功效：添加了高保湿精华，能够为干皮肌肤提供充足的水分，使皮肤保湿不干燥；还添加了柔焦光子，提亮肤色的同时帮助遮盖面部瑕疵，针对瑕疵明显的地方可以叠涂或者搭配遮瑕产品一起使用。 适用肤质：干皮、混干皮的救星，适合在干燥环境下使用。 价格：30ml/470 元左右。 色号选择：有不同色号可供挑选，如 1CO、2CO 等，其中 C 代表粉调，O 表示粉调最白，数字越大颜色越深。', 470.00, 0.92, 0, 0, '是', 10, 3, '[54]', 5, 1);

