INSERT INTO `message_info` VALUES (9, '12', '护肤小知识\n好的肌肤状态是美妆的基础。日常护肤中，要注意根据自己的肤质选择合适的护肤品。干性肌肤要注重保湿，多使用滋润型的面霜和精华；油性肌肤则要做好控油和清洁工作，但也要避免过度清洁导致皮肤屏障受损。同时，防晒也是护肤的重要环节，无论晴天还是阴天，都要记得涂抹防晒霜，预防紫外线对皮肤的伤害。', '2025-02-18 13:22:56', 0);

